const err = $input.first().json;
const wf = err.workflow || {};
const exec = err.execution || {};
const lastNode = err.execution && err.execution.lastNodeExecuted;
const msg = (err.execution && err.execution.error && err.execution.error.message) || 'Unknown error';
const stack = (err.execution && err.execution.error && err.execution.error.stack) || '';

const text = `:rotating_light: *n8n workflow failed*\n*Workflow:* ${wf.name || '?'} (id ${wf.id || '?'})\n*Failed node:* ${lastNode || '?'}\n*Execution:* ${exec.id || '?'} (mode ${exec.mode || '?'})\n*Error:* \`${msg}\`\n${stack ? '```' + stack.slice(0, 800) + '```' : ''}`;

return [{ json: { text } }];
